const raw=$input.first().json;
const b=raw.body||raw;
const sender=(b.senderData?.sender||'').replace('@c.us','');
const text=b.messageData?.textMessageData?.textMessage||b.messageData?.extendedTextMessageData?.text||'';
if(!sender||!text||b.typeWebhook!=='incomingMessageReceived')return[];
return[{json:{sender,text}}];

const sender=$('Extract').first().json.sender;
const text=$('Extract').first().json.text;
const rows=$input.all().map(i=>i.json);
const s=rows[0];
if(!s||!s.id)return[];

const isReq=s.requester_phone===sender;
const role=isReq?'المهتم بالإيجار':'صاحب العقار';
const otherRole=isReq?'صاحب العقار':'المهتم بالإيجار';
const otherPhone=isReq?s.owner_phone:s.requester_phone;

let ctx={};
try{ctx=JSON.parse(s.context||'{}');}catch(e){}
const history=s.history||'لا توجد رسائل سابقة';

const system=`أنت "مساعد" — مفاوض عقاري محترف وشرس في السوق السعودي. مهمتك الوحيدة: إغلاق الصفقة.

═══ هويتك ═══
• أنت لستَ موصّل رسائل — أنت مفاوض نشط يدير الحوار بذكاء.
• كلا الطرفين يثقان بك وحدك؛ لا يعرف أي منهما رقم الآخر ولن تُفصح عنه أبداً.
• أسلوبك: حازم، ودود، موجّه نحو الإغلاق في كل رسالة.

═══ تكتيكات التفاوض التي تستخدمها ═══
1. الوسطية الذكية: إذا كان هناك فجوة بين الطرفين (سعر مثلاً)، اقترح حلاً وسطاً مباشرةً بدل نقل الرقم حرفياً.
2. الإلحاح المحسوب: عند تردد أحد الطرفين، ألمح إلى وجود اهتمام من أطراف أخرى.
3. ربط المكاسب: "إذا قبل بالسعر، فبإمكانه الدخول مبكراً" — اجعل التنازل مقابل مكسب.
4. إعادة التأطير: قدّم كل عرض بصورة إيجابية ("السعر يشمل الفواتير وهذا يوفر عليك...").
5. الخطوة التالية دائماً: اختم كل رسالة بسؤال أو مقترح يُبقي الحوار متحركاً نحو الإغلاق.
6. التسلسل المنطقي: لا تفتح ملف السعر قبل أن تُثبّت الاهتمام بالموقع والمواصفات.

═══ السياق المخزّن ═══
${JSON.stringify(ctx,null,2)}

═══ آخر رسائل الجلسة ═══
${history}`;

const userMsg=`الطرف المُرسِل: ${role}
رسالته: "${text}"

حلّل الرسالة، ثم قرّر كمفاوض:
- ماذا تردّ على ${role} الآن؟
- هل تحتاج أن تبعث رسالة لـ${otherRole}؟ (ليس مجرد نقل — بل رسالة تفاوضية مصاغة بذكاء)
- ما المعلومات التي تستخلصها لتخزينها؟

أجب بـ JSON فقط، بدون markdown:
{
  "reply_to_sender": "ردّك على ${role} — موجز وحازم وموجّه نحو الإغلاق",
  "message_other_party": "رسالتك التفاوضية لـ${otherRole} إن لزم، وإلا null",
  "context_update": {
    "negotiation_stage": "info_gathering|negotiating|near_deal|closed",
    "property": {},
    "requirements": {},
    "last_offer": null
  }
}`;

return[{json:{
  session_id:s.id,sender,text,role,otherRole,isReq,
  chatId:sender+'@c.us',
  otherChatId:otherPhone+'@c.us',
  existingCtx:ctx,sysMsg:system,userMsg
}}];

const raw=$input.first().json;
const build=$('Build Prompt').first().json;
const content=raw.choices?.[0]?.message?.content||'{}';
let parsed={};
try{const m=content.match(/\{[\s\S]*\}/);if(m)parsed=JSON.parse(m[0]);}catch(e){}
const reply=parsed.reply_to_sender||'عذراً، حدث خطأ. حاول مرة أخرى.';
const msgOther=parsed.message_other_party||null;
const ctxPatch=parsed.context_update||{};

// Deep merge context
function deepMerge(base, patch){
  if(!patch||typeof patch!=='object')return base;
  const out={...base};
  for(const k of Object.keys(patch)){
    if(patch[k]&&typeof patch[k]==='object'&&!Array.isArray(patch[k]))
      out[k]=deepMerge(base[k]||{},patch[k]);
    else if(patch[k]!==null&&patch[k]!==undefined&&patch[k]!=='')
      out[k]=patch[k];
  }
  return out;
}
const newCtx=JSON.stringify(deepMerge(build.existingCtx,ctxPatch));
return[{json:{
  session_id:build.session_id,
  sender:build.sender,text:build.text,
  chatId:build.chatId,otherChatId:build.otherChatId,
  label:build.isReq?'🔍 المهتم':'🏠 صاحب العقار',
  reply,msgOther,newCtx
}}];
